const rows = $input.all().map(i => i.json);

const replied = rows.filter(r => r.status === 'completed_client_replied').length;
const reminders = rows.filter(r => r.status === 'reminder_draft_created').length;
const untouched = rows.filter(r => r.status === 'initial_draft_created').length;

return [{
  json: {
    total: rows.length,
    replied: replied,
    reminders: reminders,
    untouched: untouched,
    run_id: rows[0] ? rows[0].run_id : 'unknown'
  }
}];
